var e=[{id:`L2_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_SPECIAL`,text:{KOREA:`……그리고 마침내 모두 행복하게 살았답니다.`,JPN:`……そして最後には皆、幸せに暮らしましたとさ。`,ENG:`...And so, everyone lived happily ever after.`,TWN:`……從此以後過著幸福快樂的日子。`},stage:{bg:`CHURCH2`,bgm:`SKIN_SIXWING_CA_ACTOR_INTRO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_SPECIAL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_SPECIAL`,text:{KOREA:`진부하디 진부한 클리셰지만, 당신과 함께라면 분명 설레고 두근거리는 엔딩이 되겠죠.`,JPN:`陳腐なほどありふれたクリシェだけれど、あなたと一緒なら、きっと胸がときめくエンディングになるでしょう。`,ENG:`It's the oldest cliche there is, but with you, it feels thrilling.`,TWN:`雖然是老掉牙的結局，但如果對象是你，一定會是令人悸動、心跳加速的結局吧。`},stage:{bg:`CHURCH2`,bgm:`SKIN_SIXWING_CA_ACTOR_INTRO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_SPECIAL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SWAN_SIX_NULL_SPECIAL`,text:{KOREA:`하지만 지금은 조금 더 욕심을 부리고 싶네요. 그러니… 저와 키스해주시겠어요, 달링……? `,JPN:`でも今は、もう少しだけ欲張りになりたいわ。だから……私にキスしてくれませんか、ダーリン……？ `,ENG:`Still, I want a little more. So... Will you kiss me, darling...?`,TWN:`但我現在…還想再貪心一點。你…可以吻我嗎，親愛的…？`},stage:{bg:`CHURCH2`,bgm:`SKIN_SIXWING_CA_ACTOR_INTRO`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SWAN_SIX_NULL_SPECIAL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};